Assert.macro(
  "fileEquals",
  async function(filePath, contents, message) {
    this.incrementAssertionsCount();
    const hasFile = await this.fs.exists(filePath);
    if (!hasFile) {
      this.evaluate(hasFile, "expected #{this} file to exist", {
        thisObject: filePath,
        expected: "",
        actual: "",
        showDiff: false,
        prefix: message,
        operator: "exists"
      });
      return;
    }
    const onDiskContents = await this.fs.contents(filePath);
    this.evaluate(onDiskContents === contents, "expected #{this} file contents to equal #{exp}", {
      thisObject: filePath,
      expected: contents,
      actual: onDiskContents,
      prefix: message,
      operator: "strictEqual"
    });
  }
);
Assert.macro(
  "fileContains",
  async function(filePath, substring, message) {
    this.incrementAssertionsCount();
    const hasFile = await this.fs.exists(filePath);
    if (!hasFile) {
      this.evaluate(hasFile, "expected #{this} file to exist", {
        thisObject: filePath,
        expected: "",
        actual: "",
        showDiff: false,
        prefix: message,
        operator: "exists"
      });
      return;
    }
    const onDiskContents = await this.fs.contents(filePath);
    if (typeof substring === "string") {
      this.evaluate(
        onDiskContents.includes(substring),
        "expected #{this} file contents to contain #{exp}",
        {
          thisObject: filePath,
          expected: substring,
          actual: onDiskContents,
          prefix: message,
          operator: "containsSubset"
        }
      );
      return;
    }
    if (Array.isArray(substring)) {
      substring.forEach((one) => {
        this.evaluate(
          onDiskContents.includes(one),
          "expected #{this} file contents to contain #{exp}",
          {
            thisObject: filePath,
            expected: one,
            actual: onDiskContents,
            prefix: message,
            operator: "containsSubset"
          }
        );
      });
      return;
    }
    this.evaluate(
      substring.test(onDiskContents),
      "expected #{this} file contents to match #{exp}",
      {
        thisObject: filePath,
        expected: substring,
        actual: onDiskContents,
        prefix: message,
        showDiff: false,
        operator: "strictEqual"
      }
    );
  }
);
